sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {any} params.event
 * @param {any} params.imports
 * @param {ApiHelpers} params.helpers
 */
function handler({
    api,
    event,
    helpers,
    imports
}) {
    const getData = api.data.get_nextform_object;

    function loadingFailure() {
        api.emit('CTRL_NEXTFORM#LOADING_FAILED');
        api.setState('isLoading', false);
        api.setState('canProcess', false);
        return;
    }
    if (getData && getData.output && getData.output.result && getData.status !== 'error') {

        const nextFormData = getData.output.result;

        const nf = imports['x_snc_nf.NextFormUtil']();
        const screenData = nextFormData.screens;
        const fieldData = nextFormData.fields || {};

        if (!Array.isArray(screenData) || screenData.length < 1) {
            return loadingFailure();
        }
        var vr = nf.validateAllFields(fieldData);

        var screenCount = screenData.length;
        var currentSections = screenData[0];
        var currentScreenIndex = 0;
        var currentScreenNumber = currentScreenIndex + 1;

        // Keep screens (and other layout) in nextFormData; store fields only in `fields` state
        // to avoid duplicating the full field map.
        var layoutOnly = {};
        Object.keys(nextFormData).forEach(function(key) {
            if (key !== 'fields') {
                layoutOnly[key] = nextFormData[key];
            }
        });

        api.setState('nextFormData', layoutOnly);
        api.setState('currentScreenIndex', currentScreenIndex);
        api.setState('currentScreenNumber', currentScreenNumber);
        api.setState('screenCount', screenCount);
        api.setState('currentSections', currentSections);
        api.setState('fields', fieldData);

        api.setState('isLoaded', true);
        api.setState('isLoading', false);
        api.setState('isProcessed', false);

        api.setState('canGoNext', currentScreenNumber < screenCount);
        api.setState('canGoLast', currentScreenNumber < screenCount);
        api.setState('canGoPrevious', currentScreenNumber !== 1);
        api.setState('canGoFirst', currentScreenNumber !== 1);
        api.setState('canGoIndex', screenCount > 1);
        api.setState('canProcess', nf.canProcess({
            currentScreenNumber: api.state.currentScreenNumber,
            screenCount: api.state.screenCount,
            isProcessed: api.state.isProcessed
        }, vr));
        api.setState('canReset', false);

        api.emit('CTRL_NEXTFORM#LOADING_COMPLETED');
    } else {
        return loadingFailure();
    }
}
